   199	func TestConfigureReconciliation_SparsePOST(t *testing.T) {
   200		tests := []struct {
   201			name                string
   202			payload             string
   203			expectedUpsertCalls int
   204			expectedKeys        []string
   205		}{
   206			{
   207				name:                "single key",
   208				payload:             `{"impression_lookback_device":"240"}`,
   209				expectedUpsertCalls: 1,
   210				expectedKeys:        []string{"cpi_2_impression_lookback_device"},
   211			},
   212			{
   213				name:                "two keys",
   214				payload:             `{"impression_lookback_device":"240","engaged_view_lookback_device":"100"}`,
   215				expectedUpsertCalls: 2,
   216				expectedKeys:        []string{"cpi_2_impression_lookback_device", "cpi_2_engaged_view_lookback_device"},
   217			},
   218			{
   219				name:                "empty payload writes nothing",
   220				payload:             `{}`,
   221				expectedUpsertCalls: 0,
   222				expectedKeys:        nil,
   223			},
   224			{
   225				// Regression guard: frontend round-trips the GET response (which
   226				// includes "" placeholders for keys watson defaults). Writing ""
   227				// to postmeta would coerce to 0.0 on the watson read path and
   228				// reconcilers would reject claims as outside lookback. The handler
   229				// must skip empty values so watson keeps its engine default.
   230				name:                "empty values skipped",
   231				payload:             `{"fingerprint_lookback_window":"","impression_lookback_fingerprint":""}`,
   232				expectedUpsertCalls: 0,
   233				expectedKeys:        nil,
   234			},
   235			{
   236				// Mixed payload: real value written, empty siblings skipped.
   237				name:                "non-empty written, empty skipped",
   238				payload:             `{"impression_lookback_device":"240","fingerprint_lookback_window":""}`,
   239				expectedUpsertCalls: 1,
   240				expectedKeys:        []string{"cpi_2_impression_lookback_device"},
   241			},
   242		}
   243	
   244		for _, tc := range tests {
   245			tc := tc
