   253					[]string{"ko_cpi_campaign"}, []string{"publish"}).
   254					Return([]models.Post{{ID: 99}}, nil)
   255	
   256				capturedKeys := []string{}
   257				for _, key := range tc.expectedKeys {
   258					key := key
   259					mockAppDAO.On("UpsertPostmeta", "12345", 99, key, mock.AnythingOfType("string")).
   260						Return(nil).
   261						Run(func(args mock.Arguments) {
   262							capturedKeys = append(capturedKeys, args.String(2))
   263						})
   264				}
   265	
   266				// After the upserts, handlePost re-reads via getReconciliationRules.
   267				mockAppDAO.On("GetPostmetas", "12345", []int{99},
   268					[]string{"cpi_2_"}, mock.AnythingOfType("[]map[string]string")).
   269					Return([]models.Postmeta{}, nil).Maybe()
   270				mockAppDAO.On("GetPostmetas",
   271					mock.AnythingOfType("string"),
   272					mock.AnythingOfType("[]int"),
   273					mock.AnythingOfType("[]string"),
   274					mock.AnythingOfType("[]map[string]string")).
   275					Return([]models.Postmeta{}, nil).Maybe()
   276	
   277				base := &handlers.BaseHandler{
   278					GlobalDBInterface: mockGlobal,
   279					WatsonClient:      testdata.NewMockWatsonClient(),
   280				}
   281				h := NewConfigureReconciliation(base)
   282	
   283				req := httptest.NewRequest(http.MethodPost,
   284					"/apps/12345/configure_reconciliation?nid=2",
   285					strings.NewReader(tc.payload))
   286				rr := httptest.NewRecorder()
   287	
   288				h.handlePost(req.Context(), rr, req, "12345", mockAppDAO)
   289	
   290				assert.Equal(t, http.StatusOK, rr.Code, rr.Body.String())
   291	
   292				actualUpsertCalls := 0
   293				for _, call := range mockAppDAO.Calls {
